import{_ as e,p as l,q as i,a1 as a}from"./framework-822ca1a4.js";const t={},s=a('<h1 id="一般过去时态" tabindex="-1"><a class="header-anchor" href="#一般过去时态" aria-hidden="true">#</a> 一般过去时态</h1><p>用法：一般过去时态表示过去发生的动作或者状态。一般过去时态专门用来做一些记录或者尽力。例如故事，小说，新闻等，都需要用一般过去时态。</p><h2 id="主系表" tabindex="-1"><a class="header-anchor" href="#主系表" aria-hidden="true">#</a> 主系表</h2><p>主语 + was/were + 表语</p><p>主系表分为以下四个句型:</p><ol><li>人称代词主格 + was/were + 形容词</li></ol><ul><li>I was happy yesterday.</li><li>You were tired last night.</li><li>She was busy yesterday.</li><li>He was angry just now.</li><li>It was cheap yesterday.</li><li>We were excited yesterday.</li><li>They were sad yesterday.</li></ul><ol start="2"><li>名词 + was/were + 形容词</li></ol><ul><li>Nick was tired last night.</li><li>Guangxi was poor before.</li><li>Nick and Jack were busy yesterday.</li><li>Asia and Africa were poor before.</li><li>The student was happy yesterday.</li><li>My computer was expensive before.</li><li>Teachers were busy before.</li><li>The teachers were busy yesterday.</li><li>Sesame oil was expensive in the past.</li><li>The sesame oil was hot just now.</li></ul><ol start="3"><li>人称代词主格 + was/were + 名词</li></ol><ul><li>I was a driver last year.</li><li>You were a leader last year.</li><li>She was a singer before.</li><li>He was a celebrity last year.</li><li>It was temple in the past.</li><li>We were students before.</li><li>They were my fans before.</li></ul><ol start="4"><li>名词 + was/were + 名词</li></ol><ul><li>Nick was a teacher last year.</li><li>My teacher was Nick last year.</li><li>The doctor was my fan last year.</li></ul><p>变否定句，在 was/were 后面加一个否定词 not。</p><ul><li>I wasn&#39;t a teacher last year.</li><li>She wasn&#39;t busy yesterday.</li><li>My friends weren&#39;t tired last night.</li></ul><p>变一般疑问句，把 was/were 移到句首。</p><ul><li>Was she sad last night?</li><li>Were you a teacher last year?</li></ul><h2 id="主谓宾" tabindex="-1"><a class="header-anchor" href="#主谓宾" aria-hidden="true">#</a> 主谓宾</h2><ol><li>主语 + 不及物动词过去式 + 状语</li></ol><ul><li>She cried yesterday.</li><li>They danced last night.</li><li>It ran just now.</li><li>We stayed last night.</li><li>My grandfather coughed last night.</li><li>These aunts danced just nwo.</li><li>Her daughter cried yesterday.</li></ul><ol start="2"><li>主语 + 及物动词过去式 + 宾语 + 状语</li></ol><ul><li>I bought a book yesterday.</li><li>She helped an old man just now.</li><li>They cooked beef this morning.</li><li>It are my peanuts last night.</li><li>My fans bought many gifts yesterday.</li><li>Her father killed a fish just now.</li><li>His wife called him last night.</li></ul><ol start="3"><li>主语 + 双宾动词过去式 + 间接宾语 + 直接宾语 + 状语</li><li>主语 + 特定及物动词过去式 + 宾语 + 宾补 + 状语</li></ol><p>变否定句</p><ul><li>His wife didn&#39;t call him last night.</li><li>I didn&#39;t buy a book yesterday.</li></ul><p>变一般疑问句</p><ul><li>Did his wife call him last night?</li><li>Did you buy a book yesterday?</li></ul>',27),r=[s];function h(n,o){return l(),i("div",null,r)}const y=e(t,[["render",h],["__file","past-tense.html.vue"]]);export{y as default};
